import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.AnnotationConfigApplicationContext;
import org.springframework.context.annotation.ComponentScan;
import org.springframework.context.annotation.Configuration;

// 1. Dependency Bean
@Service
class EmailService {
    public void sendEmail(String msg) {
        System.out.println("Email Sent: " + msg);
    }
}

// 2. Dependent Bean
@Service
class NotificationService {
    private final EmailService emailService;

    // Constructor Injection (Best Practice)
    @Autowired
    public NotificationService(EmailService emailService) {
        this.emailService = emailService;
    }

    public void notifyUser() {
        emailService.sendEmail("Welcome to the Spring Framework!");
    }
}

// 3. Configuration Class
@Configuration
@ComponentScan(basePackages = "") // Scans the current package for components
class AppConfig {}

public class SpringDemo {
    public static void main(String[] args) {
        // Initialize the IoC Container
        var context = new AnnotationConfigApplicationContext(AppConfig.class);

        // Retrieve the bean from the container
        NotificationService service = context.getBean(NotificationService.class);
        service.notifyUser();

        // Close context to release resources
        context.close();
    }
}

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@SpringBootApplication
public class RestApiApplication {
    public static void main(String[] args) {
        // Bootstraps the application and starts the embedded web server
        SpringApplication.run(RestApiApplication.class, args);
    }
}

@RestController
class GreetingController {

    // Maps HTTP GET requests to the /api/greet endpoint
    @GetMapping("/api/greet")
    public String greetUser(@RequestParam(value = "name", defaultValue = "World") String name) {
        return "Hello, " + name + "! Welcome to Spring Boot.";
    }
}

import org.aspectj.lang.annotation.Aspect;
import org.aspectj.lang.annotation.Before;
import org.springframework.stereotype.Component;
import org.springframework.stereotype.Service;
import org.springframework.context.annotation.AnnotationConfigApplicationContext;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.EnableAspectJAutoProxy;

@Service
class PaymentService {
    public void processPayment() {
        System.out.println("Executing core business logic: Processing payment...");
    }
}

// Defining an Aspect
@Aspect
@Component
class SecurityLoggingAspect {

    // Pointcut expression matching the processPayment method in PaymentService
    @Before("execution(* PaymentService.processPayment(..))")
    public void logSecurityCheck() {
        System.out.println("[AOP LOG] Security check passed. Authorized to execute method.");
    }
}

@Configuration
@EnableAspectJAutoProxy // Enables proxy-based AOP features
@org.springframework.context.annotation.ComponentScan
class AopConfig {}

public class AopDemo {
    public static void main(String[] args) {
        var context = new AnnotationConfigApplicationContext(AopConfig.class);
        PaymentService paymentService = context.getBean(PaymentService.class);

        // The proxy intercepts this call and executes the Aspect advice first
        paymentService.processPayment();

        context.close();
    }
}

