@SpringBootApplication
@EnableCaching
public class CachingApplication {
    public static void main(String[] args) {
        SpringApplication.run(CachingApplication.class, args);
    }
}

@Service
class ExternalDataService {
    @Cacheable("apiData")
    public String fetchHeavyData(String id) {
        try {
            // Simulate network latency
            Thread.sleep(3000);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        return "Payload Data for ID: " + id;
    }
}

@RestController
class DataController {
    private final ExternalDataService dataService;

    public DataController(ExternalDataService dataService) { 
        this.dataService = dataService; 
    }

    @GetMapping("/api/data/{id}")
    public String getData(@PathVariable String id) { 
        return dataService.fetchHeavyData(id); 
    }
}
